import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Deal lifecycle","description":"From proposal to permanence.","frontmatter":{"description":"From proposal to permanence."},"headers":[],"relativePath":"concepts/deal-lifecycle.md","filePath":"concepts/deal-lifecycle.md","lastUpdated":1777130260000}'),o={name:"concepts/deal-lifecycle.md"};function l(n,e,r,d,h,p){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="deal-lifecycle" tabindex="-1">Deal lifecycle <a class="header-anchor" href="#deal-lifecycle" aria-label="Permalink to &quot;Deal lifecycle&quot;">​</a></h1><p>A Prova deal moves through five observable on-chain states. Every transition is recorded on Base. Every state is queryable via the API.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proposed → Downloading → Storing → Active → Settled</span></span>
<span class="line"><span>                                 ↘    ↓</span></span>
<span class="line"><span>                                  ↘   ↓</span></span>
<span class="line"><span>                                  Slashed (failure)</span></span></code></pre></div><h2 id="states" tabindex="-1">States <a class="header-anchor" href="#states" aria-label="Permalink to &quot;States&quot;">​</a></h2><h3 id="proposed" tabindex="-1">Proposed <a class="header-anchor" href="#proposed" aria-label="Permalink to &quot;Proposed&quot;">​</a></h3><p>On-chain. The client has called <code>proposeDeal()</code> on <code>StorageMarketplace.sol</code>, escrowed the storage fee, and the prover has been notified.</p><p>In this state:</p><ul><li>The client has paid into the escrow.</li><li>The prover has not yet acknowledged.</li><li>If the prover doesn&#39;t accept within the timeout, the client gets refunded.</li></ul><h3 id="downloading" tabindex="-1">Downloading <a class="header-anchor" href="#downloading" aria-label="Permalink to &quot;Downloading&quot;">​</a></h3><p>The prover has acknowledged and is fetching the bytes from the URL the client provided.</p><p>In this state:</p><ul><li>The prover pulls bytes from <code>sourceURL</code> (an HTTPS URL the client published).</li><li>The prover hashes the bytes as it streams; it computes the <code>piece-cid</code> independently.</li><li>If the computed cid doesn&#39;t match what&#39;s on-chain, the deal aborts and the prover is <strong>not</strong> slashed (the client provided bad data).</li></ul><h3 id="storing" tabindex="-1">Storing <a class="header-anchor" href="#storing" aria-label="Permalink to &quot;Storing&quot;">​</a></h3><p>The prover has the bytes. They&#39;re computing the on-chain commitment.</p><p>In this state:</p><ul><li>The prover writes the bytes to its disk under <code>pieces/&lt;cid&gt;</code>.</li><li>The prover prepares the first proof.</li><li>The deal is one block from being active.</li></ul><h3 id="active" tabindex="-1">Active <a class="header-anchor" href="#active" aria-label="Permalink to &quot;Active&quot;">​</a></h3><p>The deal is live. The prover posts a cryptographic proof every 30 seconds.</p><p>In this state:</p><ul><li>Each successful proof releases a slice of the escrowed payment to the prover.</li><li>Missed proofs eat into the prover&#39;s stake.</li><li>The client can retrieve the file at <code>https://prova.network/p/&lt;cid&gt;</code> (or directly from the prover via libp2p / HTTP).</li><li>The deal stays Active for the duration the client paid for (default 30 days, max 5 years).</li></ul><h3 id="settled" tabindex="-1">Settled <a class="header-anchor" href="#settled" aria-label="Permalink to &quot;Settled&quot;">​</a></h3><p>The deal has reached its end-time. The prover has been paid for every successful proof. Any remaining escrow is refunded to the client (if the prover missed proofs and got partially slashed).</p><p>The bytes can stay on the prover&#39;s disk indefinitely after Settled — the prover just isn&#39;t paid for them anymore. Some provers keep historical pieces around for popularity-driven retrieval revenue.</p><h3 id="slashed-failure-mode-not-a-normal-state" tabindex="-1">Slashed (failure mode, not a normal state) <a class="header-anchor" href="#slashed-failure-mode-not-a-normal-state" aria-label="Permalink to &quot;Slashed (failure mode, not a normal state)&quot;">​</a></h3><p>The prover missed too many proofs in a row, and the deal is terminated.</p><p>When this happens:</p><ul><li>The remaining escrow is refunded to the client.</li><li>The prover&#39;s stake is slashed (a percentage based on how badly they failed).</li><li>The piece-cid is automatically re-listed in the marketplace, so a healthy prover can pick it up.</li></ul><h2 id="querying-state" tabindex="-1">Querying state <a class="header-anchor" href="#querying-state" aria-label="Permalink to &quot;Querying state&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Via API</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://prova.network/api/files</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;authorization: Bearer pk_live_...&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.files[] | {cid, status, proofsPosted}&#39;</span></span></code></pre></div><p>Or on-chain:</p><div class="language-solidity vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">solidity</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// On Base</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">StorageMarketplace.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getDeal</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">uint256</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dealId) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">returns</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Deal</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> memory</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>The <code>Deal</code> struct includes the current status, proofs posted, escrow remaining, and last proof timestamp.</p><h2 id="time-scale" tabindex="-1">Time scale <a class="header-anchor" href="#time-scale" aria-label="Permalink to &quot;Time scale&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Typical duration</th></tr></thead><tbody><tr><td>Proposed → Downloading</td><td>&lt; 30 seconds</td></tr><tr><td>Downloading</td><td>size-dependent (≈ 1 GB/min on a good link)</td></tr><tr><td>Storing</td><td>&lt; 60 seconds</td></tr><tr><td>Active</td><td>the term you paid for</td></tr><tr><td>Active → Settled</td><td>the moment the term ends</td></tr></tbody></table><p>For a 100 MB file with a 30-day term: ~2 minutes from proposal to Active, then 30 days of daily proofs, then Settled.</p><h2 id="what-this-means-for-your-app" tabindex="-1">What this means for your app <a class="header-anchor" href="#what-this-means-for-your-app" aria-label="Permalink to &quot;What this means for your app&quot;">​</a></h2><p>If you&#39;re building on Prova, the <strong>observable state</strong> is:</p><ul><li><code>cid</code> — the content-addressed id</li><li><code>status</code> — one of <code>proposed | downloading | storing | active | settled | slashed</code></li><li><code>proofsPosted</code> — count of successful proofs since the deal went Active</li><li><code>lastProofAt</code> — timestamp of the most recent proof</li><li><code>endsAt</code> — when the deal Settles</li><li><code>escrowRemaining</code> — USDC still held in the contract</li></ul><p>A piece is <strong>safe to retrieve</strong> as soon as <code>status === &#39;active&#39;</code>. Before that, the prover may not yet have the bytes locally.</p>`,39)])])}const k=t(o,[["render",l]]);export{u as __pageData,k as default};
